const body = $input.first().json.body || $input.first().json;
const message = body.message || body.text || '';
const sessionId = body.session_id || require('crypto').randomUUID();
const customerName = body.customer_name || 'Customer';

if (!message || message.trim().length < 2) {
  throw new Error('Message is required.');
}

return [{ json: { message: message.trim(), sessionId, customerName, receivedAt: new Date().toISOString(), messageId: require('crypto').randomUUID() } }];

const original = $('Validate Input').first().json;
const aiRaw = $input.first().json;
let ai;
try {
  ai = JSON.parse(aiRaw.message?.content || aiRaw.content || '{}');
} catch (e) {
  ai = { answer: 'Sorry, I had trouble processing that. Please try again.', confidence: 0, category: 'other' };
}

return [{ json: { ...original, answer: ai.answer || '', confidence: ai.confidence || 0, category: ai.category || 'other', respondedAt: new Date().toISOString() } }];
